/* Styles généraux pour les inputs - Inspiré du login.css */

.form-control-general {
    width: 100%;
    padding: 15px 20px;
    border: 2px solid #e1e8ed;
    border-radius: 12px;
    font-size: 16px;
    transition: all 0.3s ease;
    background: #f8f9fa;
    font-family: 'Poppins', sans-serif;
    font-weight: 400;
    box-shadow: none;
}

.form-control-general:focus {
    outline: none;
    border-color: #4A90E2;
    background: white;
    box-shadow: 0 0 0 3px rgba(42, 82, 152, 0.1); /* couleur focus login.css */
    transform: translateY(-2px);
}

.form-control-general::placeholder {
    color: #a0a9b8;
    font-weight: 400;
}

.form-control-general:valid,
.form-control-general:not(:placeholder-shown):valid {
    border-color: #74e58b;
    box-shadow: 0 0 0 2px rgba(33, 136, 56, 0.15);
}

.form-control-general:invalid {
    border-color: #dc3545;
    box-shadow: 0 0 0 2px rgba(220, 53, 69, 0.15);
}

.form-control-general:not(:placeholder-shown):invalid {
    border-color: #dc3545;
    box-shadow: 0 0 0 2px rgba(220, 53, 69, 0.15);
}

.form-control-general:placeholder-shown {
    border-color: #e1e8ed;
    box-shadow: none;
}

.form-select-general {
    width: 100%;
    padding: 15px 20px;
    border: 2px solid #e1e8ed;
    border-radius: 12px;
    font-size: 16px;
    transition: all 0.3s ease;
    background: #f8f9fa;
    font-family: 'Poppins', sans-serif;
    font-weight: 400;
    cursor: pointer;
    box-shadow: none;
}

.form-select-general:focus {
    outline: none;
    border-color: #4A90E2;
    background: white;
    box-shadow: 0 0 0 3px rgba(42, 82, 152, 0.1); /* couleur focus login.css */
    transform: translateY(-2px);
}

.form-select-general:valid,
.form-select-general:not([value=""]):valid {
    border-color: #74e58b;
    box-shadow: 0 0 0 2px rgba(33, 136, 56, 0.15);
}

.form-select-general:invalid {
    border-color: #dc3545;
    box-shadow: 0 0 0 2px rgba(220, 53, 69, 0.15);
}


.form-select-general:not([value=""]):invalid {
    border-color: #dc3545;
    box-shadow: 0 0 0 2px rgba(220, 53, 69, 0.15);
}

.form-select-general[value=""] {
    border-color: #e1e8ed;
    box-shadow: none;
}

/* Style pour les floating labels avec les nouveaux inputs */
.form-floating-general {
    position: relative;
    margin-bottom: 1.5rem;
}

.form-floating-general > .form-control-general,
.form-floating-general > .form-select-general {
    height: 3.5rem;
    line-height: 1.25;
    background: #f8f9fa;
    border-radius: 12px;
    border: 2px solid #e1e8ed;
    font-size: 16px;
    padding: 1.2rem 1rem 0.5rem 1rem;
}

.form-floating-general > label {
    position: absolute;
    top: 1rem;
    left: 1rem;
    padding: 0;
    pointer-events: none;
    font-size: 16px;
    color: #6c757d;
    font-weight: 500;
    background: transparent;
    transition: 0.2s ease all;
}

.form-floating-general > .form-control-general:focus ~ label,
.form-floating-general > .form-control-general:not(:placeholder-shown) ~ label,
.form-floating-general > .form-select-general:focus ~ label,
.form-floating-general > .form-select-general:not([value=""]) ~ label {
    top: 0.3rem;
    left: 1rem;
    font-size: 13px;
    color: #4A90E2;
    opacity: 0.85;
    background: #f8f9fa;
    padding: 0 4px;
}

.form-floating-general > .form-control-general::placeholder {
    color: transparent;
}

/* Animation pour les groupes de formulaires */
.form-group-general {
    animation: fadeInUp 0.6s ease-out;
    animation-fill-mode: both;
}

.form-group-general:nth-child(1) { animation-delay: 0.1s; }
.form-group-general:nth-child(2) { animation-delay: 0.15s; }
.form-group-general:nth-child(3) { animation-delay: 0.2s; }
.form-group-general:nth-child(4) { animation-delay: 0.25s; }
.form-group-general:nth-child(5) { animation-delay: 0.3s; }

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
